<script>
   $(document).ready(function () {
    var speedValue = window.innerWidth <= 768 ? 6000 : 6000; // Faster speed for mobile
	 var slidesSetting = window.innerWidth <= 768 ? "auto" : 4; // Faster speed for mobile

    var swiper = new Swiper('.swiper-container', {
        autoplay: {
            delay: 1,
            disableOnInteraction: false,
        },
        speed: speedValue,
        slidesPerView: slidesSetting,
        loop: true,
        spaceBetween: 0,
        freeMode: true,
    });
});


    jQuery(document).ready(function($) {

        $('.counter-new').each(function() {
            var $this = $(this),
                countTo = $this.attr('data-count');

            $({ countNum: $this.text()}).animate({
                    countNum: countTo
                },
                {
                    duration: 4000,
                    easing:'linear',
                    step: function() {
                        $this.text(Math.floor(this.countNum));
                    },
                    complete: function() {
                        $this.text(this.countNum);
                    }

                });

        });
    });

</script>

